/**
 * Client-side photo compression before upload.
 * Resizes large photos to max dimension and compresses to JPEG.
 * Reduces 5MB phone photos to ~200KB without visible quality loss.
 *
 * Safe to call on any File/Blob — returns original if compression
 * is unnecessary or fails (e.g. HEIC on older browsers).
 */

const MAX_DIMENSION = 1200 // px — sufficient for face analysis
const JPEG_QUALITY = 0.8
const SKIP_BELOW_KB = 300 // don't compress already-small files

/**
 * Compress a photo File/Blob for upload.
 * @param {File|Blob} file — image file to compress
 * @param {object} [opts] — optional overrides
 * @param {number} [opts.maxDimension=1200] — max width/height in px
 * @param {number} [opts.quality=0.8] — JPEG quality 0-1
 * @param {number} [opts.skipBelowKB=300] — skip if file is already below this size
 * @returns {Promise<File>} compressed file, or original if already small/compression fails
 */
export async function compressPhoto(file, opts = {}) {
  if (!file || !file.type?.startsWith('image/')) return file

  const maxDim = opts.maxDimension || MAX_DIMENSION
  const quality = opts.quality || JPEG_QUALITY
  const skipBelow = (opts.skipBelowKB || SKIP_BELOW_KB) * 1024

  // Skip if already small
  if (file.size < skipBelow) return file

  try {
    const bitmap = await createImageBitmap(file)
    const { width, height } = bitmap

    // Skip if already within bounds
    if (width <= maxDim && height <= maxDim) {
      bitmap.close()
      return file
    }

    // Calculate scaled dimensions preserving aspect ratio
    const scale = maxDim / Math.max(width, height)
    const newW = Math.round(width * scale)
    const newH = Math.round(height * scale)

    // Draw to offscreen canvas
    const canvas = new OffscreenCanvas(newW, newH)
    const ctx = canvas.getContext('2d')
    ctx.drawImage(bitmap, 0, 0, newW, newH)
    bitmap.close()

    // Convert to compressed JPEG blob
    const blob = await canvas.convertToBlob({ type: 'image/jpeg', quality })

    // Wrap as File to preserve .name
    return new File(
      [blob],
      file.name?.replace(/\.\w+$/, '.jpg') || 'photo.jpg',
      { type: 'image/jpeg', lastModified: file.lastModified || Date.now() }
    )
  } catch {
    // If compression fails (e.g. HEIC on older browser), return original
    return file
  }
}
